import {
  Entity,
  PrimaryGeneratedColumn,
  Column,
  CreateDateColumn,
  UpdateDateColumn,
} from "typeorm";

@Entity()
export class Product {
  @PrimaryGeneratedColumn()
  id: number;

  @Column()
  name: string;

  @Column("text")
  description: string;

  @Column("decimal", { precision: 10, scale: 2 }) // Exemple pour les prix décimaux
  price: number;

  @Column()
  stock: number;

  @Column({ nullable: true })
  weight: string; // Poids du sachet (ex : "250g", "1kg")

  @Column({ nullable: true })
  origin: string; // Provenance (ex : "Inde", "Maroc")

  @Column({ default: true })
  availability: boolean; // Produit disponible ou non

  @Column({ nullable: true })
  imageURL: string;

  @CreateDateColumn()
  createdAt: Date;

  @UpdateDateColumn()
  updatedAt: Date;
}
